<?phprequire_once '../php-dbManager/init_session.php';require_once '../php-dbManager/FaqManager.php';/** @var string $destinazione_profilo */$lista_faq_db = FaqManager::getFaq();$html_faq_dinamico = "";if (count($lista_faq_db) > 0) {    foreach ($lista_faq_db as $singola_faq) {        // funzione per pulì i dati        $domanda_sicura = htmlspecialchars($singola_faq['testo_domanda']);        $risposta_sicura = htmlspecialchars($singola_faq['testo_risposta']);        // costruzione blocco da buttare dentro html        $html_faq_dinamico .= '<details class="faq-item">';        $html_faq_dinamico .= '    <summary>' . $domanda_sicura . '</summary>';        $html_faq_dinamico .= '    <div class="faq-content">';        $html_faq_dinamico .= '        <p>' . $risposta_sicura . '</p>';        $html_faq_dinamico .= '    </div>';        $html_faq_dinamico .= '</details>';    }} else {    // mostro se il db è vuoto    $html_faq_dinamico = "<p>Al momento non ci sono domande frequenti disponibili.</p>";}$pagina_html = file_get_contents('../html/faq.html');$pagina_html = str_replace('[lista_faq]', $html_faq_dinamico, $pagina_html);$pagina_html = str_replace('[link_profilo]', $destinazione_profilo, $pagina_html); //se è loggato innietto il link alla sua areautenteecho $pagina_html;